request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?choreo
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?start) AS ?startCount)
  (COUNT(DISTINCT ?end) AS ?endCount)
  (COUNT(DISTINCT ?catch) AS ?catchCount)
  (COUNT(DISTINCT ?xor) AS ?xorCount)
  (COUNT(DISTINCT ?and) AS ?andCount)
  (COUNT(DISTINCT ?eventgw) AS ?eventGwCount)
  (COUNT(DISTINCT ?msgFlow) AS ?msgFlowCount)
  (COUNT(DISTINCT ?seqFlow) AS ?seqFlowCount)
WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "3d0f07f9b84c4e31bbca562f472c8885" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .

  OPTIONAL { ?task a bboExt:ChoreographyTask . ?task tai:belongsTo ?choreo . }
  OPTIONAL { ?start a bboExt:StartEvent . ?start tai:belongsTo ?choreo . }
  OPTIONAL { ?end a bboExt:EndEvent . ?end tai:belongsTo ?choreo . }
  OPTIONAL { ?catch a bboExt:IntermediateCatchEvent . ?catch tai:belongsTo ?choreo . }
  OPTIONAL { ?xor a bboExt:ExclusiveGateway . ?xor tai:belongsTo ?choreo . }
  OPTIONAL { ?and a bboExt:ParallelGateway . ?and tai:belongsTo ?choreo . }
  OPTIONAL { ?eventgw a bboExt:EventBasedGateway . ?eventgw tai:belongsTo ?choreo . }
  OPTIONAL { ?msgFlow a bboExt:MessageFlow . ?msgFlow tai:belongsTo ?choreo . }
  OPTIONAL { ?seqFlow a bbo:SequenceFlow . ?seqFlow tai:belongsTo ?choreo . }
}
GROUP BY ?choreo
ORDER BY DESC(?seqFlowCount)
LIMIT 25
